const Q_PHYSICS_2022_MODEL_V=[{"id": "objective>Physics>2022 Model V>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electron jumps from one energy level to another in an atom radiating 5.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>Joules. If planck's constant is 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js, what is the wavelength of the radiation ?  <br/> [c = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>] </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.81 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.81 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.81 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.81 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">∆E = E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> - E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = hf <br/> ∆E = 5.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> = 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>f <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">c<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5.2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.6×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>×3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span><hr size=\"1\" />5.2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span></td></tr></table></div> <br/> λ = 3.81 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m</div>", "topic": "ELEMENTARY MODERN PHYSICS : ENERGY LEVELS AND SPECTRA"}, {"id": "objective>Physics>2022 Model V>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are applications of x-rays? <br/> I. X-rays are used to treat cancer <br/> II. X-rays are used for detecting faults, cracks and flaws in metal casting <br/> III. X-rays are used in the investigation of structure of crystals <br/> IV. X-rays are used as a diagnostic tool in medicine to detect feature of bones, foreign bodies like bullets and stones in the body.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I,II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III, IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Applications of X-rays <br/> - X-rays are used to treat cancer <br/> - X-rays are used for detecting faults, cracks and flaws in metal casting <br/> - X-rays are used in the investigation of structure of crystals <br/> - X-rays are used as a diagnostic tool in medicine to detect feature of bones, foreign bodies like bullets and stones in the body.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2022 Model V>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A building can be adequately protected from lightning by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">using asbestos for the roof of the house </div>", "<div style=\"font-family:Cambria;font-size:17px;\">planting trees around the house </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixing a long copper strip from the ground along the outside wall to a sharp vertical spike </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixing a long ebonite rod with sharp spikes to the outsides wall</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">a long copper strip is attached to a building to protect it from lightning strokes by providing an easier path for the current to flow to earth rather than through the building. </div>", "topic": "ELECTROSTATICS : ELECTRIC DISCHARGE AND LIGHTNING"}, {"id": "objective>Physics>2022 Model V>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The image of an object placed at 2f from a concave mirror is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">real, diminished and inverted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">real, magnified and inverted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virtual, same size and inverted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">real, same size and inverted </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The image of an object placed at 2f from a concave mirror is real, same size and inverted </div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2022 Model V>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the distance between a node and antinode for a transverse wave?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice the wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three quarters of the wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one-quarter of the wavelength</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distance between a node and antinode is one-quarter of a wavelength.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2022 Model V>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Transverse and longitudinal waves travelling in the same direction in a medium differ essentially in their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direction of vibration of the particles of the medium.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between transverse and longitudinal waves is the direction of vibration of the medium.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2022 Model V>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A magnet field is a region in which a magnetic force can be detected.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A line of force is a line along which a magnetic north pole would tend to move if it were free.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic fields are scalar quantities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutral points are obtained where the Earth's magnetic field is exactly equal and opposite to that due to a magnet.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement that is not correct is 'Magnetic fields are scalar quantities'. Magnetic fields are vector quantities, not scalar quantities. A vector quantity has both magnitude and direction, while a scalar quantity has only magnitude.</div>", "topic": "MAGNETIC FIELD"}, {"id": "objective>Physics>2022 Model V>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a scalar quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mass</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weight is not a scalar quantity as it has both magnitude and direction.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2022 Model V>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the magnetic force experienced by an electron of charge 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C projected into a magnetic field of flux density 10T, with a velocity of 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, in a direction at 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> to the field</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = qvBsinθ <br/> q = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C, v = 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, B = 10T, θ =30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> F = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> × 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span> × 10 × sin30 <br/> F = 2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>N</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2022 Model V>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine has a velocity ratio 10 and is 80% efficient. What effort would be needed to lift a load of 500N with the aid of this machine.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">62.5N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">86.25N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.5N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />E</td></tr></table></div> <br/> V.R = 10 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Eff</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">500<hr size=\"1\" />E</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">500<hr size=\"1\" />10E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500×100<hr size=\"1\" />80×10</td></tr></table></div> <br/> E =  62.5N</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2022 Model V>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rise or fall of a liquid in a narrow tube, is due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the friction between the walls of the tube and the liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the viscosity of the liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the osmotic pressure of the liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the surface tension of the liquid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rise or fall of a liquid in a narrow tube is called capillarity and it is due to surface tension.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2022 Model V>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object placed 36cm from a converging lens of focal length 24cm, forms a real image which is 8cm high. What is the height of the object.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> f = 24cm, u = 36cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />24</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />36</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />24</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />36</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3-2<hr size=\"1\" />72</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />72</td></tr></table></div> <br/> v = 72cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">image height<hr size=\"1\" />object height</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">image distance<hr size=\"1\" />object distance</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">72<hr size=\"1\" />36</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />object height</td></tr></table></div> <br/> object height = 4cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2022 Model V>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric appliance takes 12A when operated on a 240V supply. Find the cost of operating the appliance for 20 hours at ₦15 per kWh</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦864</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦846</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦648</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦468</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">IV</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">240</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2880watts</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2880<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.88kW</td></tr></table></div> <br/> Energy consumed = power × time = 2.88 × 20 = 57.6kWh <br/> If 1kWh = ₦15 <br/> 57.6kWh = ₦864</div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model V>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what frequency will a 50μF capacitor have a reactance of 800Ω ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2πfC</td></tr></table></div> <br/> X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = 800Ω, C = 50μF <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">800</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2×π×f×50×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />800×2×π×50×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> f = 3.979Hz <br/> f = 4Hz</div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2022 Model V>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature above which certain materials lose their permanent magnetic properties is called ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Curie point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breaking point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Curie point or Curie temperature is the temperature above which certain materials lose their permanent magnetic properties.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2022 Model V>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is quantity of heat required to raise the temperature of 450g of a solid block by 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C. if the specific heat capacity of the solid block is 520Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2340J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4578J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1250J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">348J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of heat required to raise the temperature of a substance is given by the formula Q = mcΔT. Substituting the given values gives Q = 2340J.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2022 Model V>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the heat produced in an electric coil of resistance 45Ω when a current of 12A flows through it for 20 minutes.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.78 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.78 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.78 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heat produced in an electric coil can be calculated using Joule's law of heating, which states that the heat produced in a resistor is directly proportional to the square of the current provided, the resistance of the circuit, and the time for which the current is passed.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model V>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How long does it take a 840W heater to raise the temperature of 3.2kg of water from 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C to 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C [specific heat capacity of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">800s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The time taken to raise the temperature of a substance can be calculated using the formula Q = mcΔT, where Q is the heat supplied, m is the mass of the substance, c is the specific heat capacity, and ΔT is the change in temperature.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2022 Model V>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mass of 20kg is moving in a circular path of radius 5m with a uniform speed of 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Find the centripetal force.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6400N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8200N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3800N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4200N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Centripetal</td><td style=\"text-align:center;\">force</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td></tr></table></div> <br/> mass = 20kg, v = 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, r = 5m <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20×40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />5</td></tr></table></div>  <br/> F = 6400N</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2022 Model V>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Calculate the voltage in the circuit above if the current passing through the circuit is 10A.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">130V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">260V </div>", "<div style=\"font-family:Cambria;font-size:17px;\">560V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effective resistance = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> R = 5 + 8 = 13 ohms <br/> V = IR <br/> V = 10 × 13 <br/>  V = 130V</div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW~~CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2022 Model V>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When white light is dispersed by a spectrometer, the component having the lowest frequency is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Violet</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When white light is dispersed, Red has the lowest frequency while violet has the highest frequency. <br/> </div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2022 Model V>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is/are true about distance and displacement <br/> I. distance is a scalar quantity while displacement is a vector quantity <br/> II. they are both vector quantities <br/> III. distance has only magnitude while displacement has both magnitude and direction</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- Distance is a scalar quantity while displacement is a vector quantity <br/> - Distance has only magnitude while displacement has both magnitude and direction</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2022 Model V>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the work done against gravity in order to lift a body of mass 25kg through a height of 14m.  <br/> [Take g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3500J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2500J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work done against gravity is calculated using the formula W = mgh, where m is the mass of the body, g is the acceleration due to gravity, and h is the height. Substituting the given values, we get W = 25kg * 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> * 14m = 3500J.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model V>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non-luminous object can be seen because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflect light  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are near</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are polished</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emit light</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A non-luminous object is one that does not produce its own light, although it can still reflect light from other sources.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2022 Model V>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction in which the nucleus of an atom splits into two approximate equal parts with the release of a huge amount of energy and neutrons is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nuclear Fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear Fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radioactivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Energy Quantization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear Fission is a reaction in which the nucleus of an atom splits into two approximate equal parts with the release of a huge amount of energy and neutrons </div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2022 Model V>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 3kg and volume 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is hung from a balance graduated in Newtons. What is the reading of the balance when the body is fully immersed in water. <br/> [ Take g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, density of water = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">34N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reading of the balance is the apparent weight of the body in water = weight in air - upthrust <br/> weight in air = 3 × 10 = 30N <br/> upthrust = volume of object × density of water × g <br/> U = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 10 = 4N  <br/> the apparent weight = 30 - 4 = 26N <br/> </div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2022 Model V>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these measuring instruments can accurately measure diameter of a pendulum bob?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">micrometer screw guage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metre rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spring balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tape rule</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A micrometer, sometimes known as a micrometer screw gauge, is a device incorporating a calibrated screw widely used for accurate measurement of components.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2022 Model V>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The majority charge carriers in P-type semiconductor are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">holes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutrons</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a p-type semiconductor, the majority charge carriers are the holes whereas in the n- type semiconductor, the majority charge carriers are the free electrons.</div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}, {"id": "objective>Physics>2022 Model V>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens when the Moon blocks the light of the Sun from reaching the Earth</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solar eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lunar eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">annular eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partial lunar eclipse</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solar eclipse occurs when the Moon blocks the light of the Sun from reaching the Earth. This is because the Moon is directly between the Earth and the Sun, blocking the Sun's light.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2022 Model V>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the superficial expansivity of a solid that has a linear expansivity of 3.14 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The superficial expansivity of a solid is given by 2 times the linear expansivity. Therefore, the superficial expansivity of the solid is 2 * 3.14 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 6.28 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "HEAT TRANSFER~~HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2022 Model V>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At what angle are the two mirrors in kaleidoscope inclined to produce multiple images?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kaleidoscope is a toy which uses the principle of inclined mirrors to produce multiple images by fixing two mirrors inclined at 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> in a tube.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2022 Model V>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the kinetic energy of a body of mass 15kg that started from rest and travelled a distance of 50m with an acceleration of 1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">750J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">650J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/> it started from rest, u = 0 <br/> a = 1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, s = 50m <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 0 + 2 × 1 × 50 <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 100 <br/> v = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">15</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> K.E = 750J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model V>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transformer has 800 turns of wire in the primary coil and 200 turns in the secondary coil.If the input voltage is 600 volts, the output voltage is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">150V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = number of turns on primary side <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = number of turns on secondary side <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = primary voltage <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = secondary voltage  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">800<hr size=\"1\" />200</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">600<hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200×600<hr size=\"1\" />800</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 150V</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2022 Model V>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lower and upper fixed points of a certain thermometer are 40cm apart. At a certain day, the length of mercury thread in the thermometer is 16cm above the ice point (0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C). What is temperature recorded by the thermometer in celsius scale. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">64<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"2022 Model V/phyutmevq34.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x - N<hr size=\"1\" />M - N</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">C - 0<hr size=\"1\" />100 - 0</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">16<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">C<hr size=\"1\" />100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100×16<hr size=\"1\" />40</td></tr></table></div> <br/> C = 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> </div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2022 Model V>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A neutral body is charged by placing a charged body near it without any contact between the two, this phenomenon is called ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electrostatic induction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Contact charging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-contact charging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electromagnetic induction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrostatic induction is the act of charging a neutral body by placing a charged body near it without any contact between the two.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2022 Model V>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable type of magnet for magnetic shielding is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">permanent magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temporary magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metalloids</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic shielding is used to block or redirect magnetic fields. The most suitable materials for this are highly permeable materials that can absorb and redirect magnetic field lines. <br/>  <br/> Temporary magnets, such as soft iron, are ideal for magnetic shielding because: <br/>  <br/> They have high magnetic permeability, meaning they easily allow magnetic field lines to pass through them. <br/>  <br/> They do not retain magnetism when the external magnetic field is removed, making them effective for shielding.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2022 Model V>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To convert an alternating current dynamo into a direct current dynamo, the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of turns in the coil is increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strength of the field magnet is increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slip rings are replaced with a split ring commutator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coil is wound on a soft iron armature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since d.c waves are in the same direcion, the purpose of the split ring commutator is to reverse the current every 180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>. This ensures that the torque continues in the same direction. The split ring commutator makes connection with the rotor coil (armature).</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2022 Model V>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Calculate the effective e.m.f. of the cells in the circuit above, if E1 = 10V, E2 = 7V, E3 = 5V and E4 = 12V</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">34V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effective e.m.f in a series connection is the addition of individual e.m.f of the cells. <br/> E = E1 + E2 + E3 + E4 <br/> E = 10 + 7 + 5 + 12 = 34V</div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2022 Model V>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Calculate the impedance in the circuit above </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">141.74Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">132.63Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">121.74Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">231.74Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Z = √(R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) <br/> R = 50Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2πfC</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2×π×60×20×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> X = 132.63Ω <br/> Z = √(50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 132.63<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>) <br/> Z = 141.74Ω</div>", "topic": "SIMPLE A. C. CIRCUITS : REACTANCE AND IMPEDANCE"}, {"id": "objective>Physics>2022 Model V>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A charge of 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C enters a magnetic field of flux density of 4.0T with a velocity of 5.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at an angle of 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> with the field. Calculate the magnitude of the force exerted on the charge by the field. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.88 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-13</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.88 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.88 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.88 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = qVBsinθ <br/> q = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C, V = 5.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, B = 4T and θ = 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> F = 1.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> × 5.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> × 4 × sin60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> F = 2.88 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>N</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}];
